// 串聯：全部相加
function series(list){
  return list.reduce((sum, r) => sum + r, 0);   // 3 + 6 = 9
}

// 並聯：先把倒數加起來，再取倒數
function parallel(list){
  const inv = list.reduce((s, r) => s + 1/r, 0); // 1/3 + 1/6 = 0.5
  return 1 / inv;                                 // 1 / 0.5 = 2
}

// 不用背，直接把電阻的兩個函式『對調』來用
const capParallel = list => series(list);   // 電容並聯 = 相加   → 9
const capSeries   = list => parallel(list); // 電容串聯 = 倒數和 → 2

// 程式邏輯只有一份，電容永遠套到『相反』那條，不會錯

function ohm(V, I, R){
  if (V == null) V = I * R;        // 缺電壓：I×R
  else if (I == null) I = V / R;   // 缺電流：V÷R
  else if (R == null) R = V / I;   // 缺電阻：V÷I
  const P = V * I;                 // 功率
  return { V, I, R, P };
}

// ohm(110, 0.5, null) → { V:110, I:0.5, R:220, P:55 }
